using UnityEngine;

/// <summary>
/// Recompensa de missão — ao recolher, entrega os itens/recursos configurados
/// (<see cref="itemRewards"/>, <see cref="sementes"/>, <see cref="runasDeGaia"/>)
/// e, opcionalmente, marca <see cref="mission"/> como concluída
/// (<c>MissionManager.CompleteMission</c>).
///
/// Útil para missões cuja recompensa é representada por um objecto físico no
/// mundo (ex: um baú/item especial que aparece só depois de a missão avançar).
/// Para missões cuja conclusão já é tratada por diálogo/Acção de NPC, deixar
/// <see cref="mission"/> vazio e usar isto apenas como "entrega de itens".
/// </summary>
public class MissionRewardPickup : PickupBase
{
    [Header("Missão (opcional)")]
    [Tooltip("Se definida, marca esta missão como concluída ao recolher (MissionManager.CompleteMission). Deixar vazio se a conclusão da missão já é tratada por outro meio (diálogo/Acção de NPC).")]
    public MissionData mission;

    [Header("Recompensa")]
    [Tooltip("Itens entregues ao recolher (PlayerProgress.AddItem — respeita ItemData.maxQuantity / savedAsCollected).")]
    public PickupLootEntry[] itemRewards;

    [Tooltip("Sementes concedidas (0 = nenhuma).")]
    [Min(0)] public int sementes = 0;

    [Tooltip("Runas de Gaia concedidas (0 = nenhuma).")]
    [Min(0)] public int runasDeGaia = 0;

    public override PickupType Type => PickupType.MissionReward;

    protected override void GrantReward()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        if (itemRewards != null)
        {
            foreach (var entry in itemRewards)
            {
                if (entry == null || entry.item == null) continue;
                progress.AddItem(entry.item, entry.amount);
            }
        }

        if (sementes > 0) progress.GiveSementes(sementes);

        if (runasDeGaia > 0)
        {
            progress.GiveRunasDeGaia(runasDeGaia);

            if (area != null)
                for (int i = 0; i < runasDeGaia; i++) progress.AddRunaFound(area);
        }

        if (mission != null) MissionManager.Instance?.CompleteMission(mission);
    }
}
